var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토, 음료수 받아라.","JPN":"湊、これでも飲めよ。","ENG":"Minato, here is your drink.","TWN":"南裕夏，飲料拿去。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 고마워.","JPN":"ああ、ありがとう。","ENG":"Ah, thanks.","TWN":"喔，謝謝你。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그나저나 신기하네. 다들 피난 얘기를 하고 있는데 아직도 영업하는 편의점이 있다니.","JPN":"それにしても不思議だな。\\nみんなが避難の話をしてるこんな状況で営業してるコンビニがあるなんて。","ENG":"That’s curious. Everyone’s evacuating, but a convenience store is still in business.","TWN":"不過還真奇妙，大家都忙著逃難，怎麼還有便利商店在營業？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아포칼립스라는 상호명이 그냥 멋으로 붙은 건 아니란 거겠지.","JPN":"アポカリプスって名前は伊達じゃないってことなんだろう。","ENG":"I guess it’s called Apocalypse for a reason.","TWN":"知道阿波卡利斯便利商店的厲害了吧！"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"라면은 다 익은 것 같은데?","JPN":"カップ麺そろそろ食べごろだぞ。","ENG":"Your cup noodle looks ready.","TWN":"泡麵應該可以吃了吧？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Okay.","TWN":"嗯。"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"나야 상관없지만, 마사키 너까지 라면으로 괜찮겠어?","JPN":"僕はいいけど、雅紀までカップ麺でいいの？","ENG":"I’m okay with this, but are you sure you’ll be okay with noodles?","TWN":"我是無所謂，但你可以吃泡麵嗎？"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"됐어. 이 새벽에 본부에서 밥 달라고 했다간, 낫토에 된장국이나 먹게 될 게 뻔하니까.","JPN":"ああ。どうせ本部に戻ったってこんな夜明けじゃ\\n納豆にみそ汁程度しか出ないしな。","ENG":"I don’t care. If I ask the Alliance for a meal at this hour, they will feed me fermented beans and soup.","TWN":"只能這樣囉～凌晨跟總部討飯吃，應該只會得到納豆和味噌湯吧？"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하야미 씨는…… 연합에 머물고 있다가 붙잡힌 거지?","JPN":"速水さんは……連合に留まっていて捕まったんだよね？","ENG":"Hayami... They apprehended her while she was staying with the Alliance, right?","TWN":"速水早苗…是停留在聯盟時被逮到的吧？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"그래, 재판에 회부되기 전까진 감옥에 가둬 둘 거라고 했어.","JPN":"そうだな。裁判が開かれるまでは拘束するらしい。","ENG":"Yes. They said she will be locked up until the trial.","TWN":"嗯嗯，聽說受審前會先關在監牢裡。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아직도 잘 실감이 나지 않아.","JPN":"まだ信じられないな。","ENG":"I can’t believe it.","TWN":"我到現在還是無法相信。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"우릴 치료해줬던 그 사람이 치나츠를 죽이려고 했다니.","JPN":"僕たちを助けてくれた人が千夏を暗殺しようとしたなんて。","ENG":"She saved our lives, yet she tried to kill Chinatsu?","TWN":"那個治療我們的人，竟然想要殺千夏？"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"연합 사람들의 관계가 마냥 좋지만은 않다는 건 알고 있었지만…… 이 정도로 심각한 원한이 있는 줄은 몰랐어.","JPN":"連合は複雑な人間関係があることはわかったけど……\\nこんなに深刻だとは思ってなかった。","ENG":"I knew the Alliance members didn’t really get along... but I didn’t expect their grudges to run so deep.","TWN":"我知道聯盟成員間的感情不太好…只是沒想到有這麼大的仇恨。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"이제 와서 특별히 이상할 것도 없지.","JPN":"別におかしなことではないんだ。","ENG":"There’s nothing to be surprised about.","TWN":"現在回想起來，其實也沒什麼好奇怪的。"},"stage":{"bg":"STORE2","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하야미는 원래 나나하라 당주를 지키는 호위무사 가문이었거든.","JPN":"速水家は元々七原家当主を守る護衛の一族だったからな。","ENG":"The Hayami family was traditionally a bodyguard family that protected Nanahara family.","TWN":"速水原本是守護七原堂主的護衛武士家族。"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"호위무사? 그건 치나츠의 동생이 맡고 있는 거 아니었어?","JPN":"護衛？　今は千夏の妹がやっているよね？","ENG":"Bodyguard? I thought Chinatsu’s sister was the bodyguard.","TWN":"護衛武士？那不是千夏的妹妹在負責的嗎？"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"나나하라 가문은 원래 무사를 키우지 않아.","JPN":"七原家は元々武士を育成しない。","ENG":"The Nanahara family is not a warrior clan.","TWN":"七原家族原本是不會培養武士的。"},"stage":{"bg":"STORE2","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};